     7→export class ProcessUserPromotion {
     8→  constructor(
     9→    private getUser: GetUserNRC,
    10→    private getAccessPoint: GetAccessPoint,
    11→    private postPromotion: PostPromotion,
    12→    private sqsDLQService: SqsService,
    13→    private sqsEmailService: SqsService,
    14→    private sqsService: SqsService
    15→  ) {}
    16→
    17→  async execute(event: any): Promise<PostPromotionResponse> {
    18→    try {
    19→      const body = JSON.parse(event.body);
    20→      const userNRC = await this.getUser.execute(
    21→        COMPANY_IDENTIFICATION,
    22→        body.identification
    23→      );
    24→
    25→      const productIdentification = await this.getAccessPoint.execute(
