import { SQS, DeleteMessageCommand} from '@aws-sdk/client-sqs';
import { Console } from 'libStpInvoke';

export class SqsService {
  private sqs: SQS;
  private url: string;

  constructor(sqs: SQS, url: string) {
    this.sqs = sqs;
    this.url = url;
  }

  async sendToSQS(message: Object): Promise<void> {
    try {
      await this.sqs
        .sendMessage({
          QueueUrl: this.url,
          MessageBody: JSON.stringify(message), 
        });
    } catch (error) {
      Console.error('Failed to send message to SQS:', error);
      throw error; 
    }
  }

  async deleteFromSQS(receiptHandle: string): Promise<void> {
    try {
      await this.sqs.send(new DeleteMessageCommand({
        QueueUrl: this.url,
        ReceiptHandle: receiptHandle,
      }));
    } catch (error) {
      Console.error('Failed to delete message from SQS:', error);
      throw error;
    }
  }
}

