import { SqsService } from "../../infrastructure";
import { GetAccessPoint, GetUserNRC, PostPromotion, ProcessUserPromotion } from "../../application";
import { COMPANY_IDENTIFICATION } from "../../constants";

describe("ProcessUserPromotion", () => {
  let processUserPromotion: ProcessUserPromotion;
  let getUser: jest.Mocked<GetUserNRC>;
  let getAccessPoint: jest.Mocked<GetAccessPoint>;
  let postPromotion: jest.Mocked<PostPromotion>;
  let dlqService: jest.Mocked<SqsService>;
  let sqsEmailService: jest.Mocked<SqsService>;
  let sqsService: jest.Mocked<SqsService>;

  beforeEach(() => {
    getUser = {
      execute: jest.fn(),
    } as unknown as jest.Mocked<GetUserNRC>;

    getAccessPoint = {
      execute: jest.fn(),
    } as unknown as jest.Mocked<GetAccessPoint>;

    postPromotion = {
      execute: jest.fn(),
    } as unknown as jest.Mocked<PostPromotion>;

    dlqService = {
      sendToSQS: jest.fn(),
    } as unknown as jest.Mocked<SqsService>;

    sqsEmailService = {
      sendToSQS: jest.fn(),
    } as unknown as jest.Mocked<SqsService>;

    sqsService = {
      deleteFromSQS: jest.fn(),
    } as unknown as jest.Mocked<SqsService>;

    processUserPromotion = new ProcessUserPromotion(
      getUser,
      getAccessPoint,
      postPromotion,
      dlqService,
      sqsEmailService,
      sqsService
    );
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it("should process user promotion successfully", async () => {
    const event = {
      body: JSON.stringify({
        identification: "test-id",
        productCode: "1",
        productDescription: "Test Product",
        promotionCode: "2",
        promotionDescription: "Test Promotion",
        promotionValidityDate: "2024-12-31",
        postingDate: "2024-12-01",
      }),
    };

    (getUser.execute as jest.Mock).mockResolvedValue("user-nrc");
    (getAccessPoint.execute as jest.Mock).mockResolvedValue({ identification: "product-id" });
    (postPromotion.execute as jest.Mock).mockResolvedValue({});

    await processUserPromotion.execute(event);

    expect(getUser.execute).toHaveBeenCalledWith(COMPANY_IDENTIFICATION, "test-id");
    expect(getAccessPoint.execute).toHaveBeenCalledWith(COMPANY_IDENTIFICATION, "user-nrc");
    expect(postPromotion.execute).toHaveBeenCalledWith("user-nrc", "product-id", COMPANY_IDENTIFICATION);
    expect(dlqService.sendToSQS).not.toHaveBeenCalled();
    expect(sqsEmailService.sendToSQS).not.toHaveBeenCalled();
    expect(sqsService.deleteFromSQS).not.toHaveBeenCalled();
  });

  it("should send event to DLQ and process email event if an error occurs", async () => {
    const event = {
      messageId: "mock-message-id",
      receiptHandle: "mock-receipt-handle",
      body: JSON.stringify({
        identification: "test-id",
        productCode: "1",
        productDescription: "Test Product",
        promotionCode: "2",
        promotionDescription: "Test Promotion",
        promotionValidityDate: "2024-12-31",
        postingDate: "2024-12-01",
      }),
    };

    (getUser.execute as jest.Mock).mockRejectedValue(new Error("Could not load credentials from any providers"));

    await expect(processUserPromotion.execute(event)).rejects.toThrow("Could not load credentials from any providers");

    const expectedBody = {
      ...JSON.parse(event.body),
      error: "Could not load credentials from any providers",
      errorType: "system",
    };

    const expectedDLQMessage = {
      ...event,
      body: JSON.stringify(expectedBody),
    };

    const expectedEmailMessage = {
      source: "NTS-App-Fintech-FeeExemption",
      messageId: "mock-message-id",
      body: expectedBody,
    };

    expect(dlqService.sendToSQS).toHaveBeenCalledWith(expectedDLQMessage);
    expect(sqsEmailService.sendToSQS).toHaveBeenCalledWith(expectedEmailMessage);
    expect(sqsService.deleteFromSQS).toHaveBeenCalledWith("mock-receipt-handle");
  });

  it("should handle SQS delete failure gracefully", async () => {
    const event = {
      body: JSON.stringify({
        identification: "test-id",
        productCode: "1",
        productDescription: "Test Product",
        promotionCode: "2",
        promotionDescription: "Test Promotion",
        promotionValidityDate: "2024-12-31",
        postingDate: "2024-12-01",
      }),
      receiptHandle: "mock-receipt-handle",
      messageId: "mock-message-id",
    };

    const mockError = new Error("SQS delete error");

    (getUser.execute as jest.Mock).mockRejectedValue(new Error("Could not load credentials from any providers"));
    (dlqService.sendToSQS as jest.Mock).mockResolvedValue(undefined);
    (sqsEmailService.sendToSQS as jest.Mock).mockResolvedValue(undefined);
    (sqsService.deleteFromSQS as jest.Mock).mockRejectedValue(mockError);

    await expect(processUserPromotion.execute(event)).rejects.toThrow("SQS delete error");

    const expectedBody = {
      ...JSON.parse(event.body),
      error: "Could not load credentials from any providers",
      errorType: "system",
    };

    const expectedDLQMessage = {
      ...event,
      body: JSON.stringify(expectedBody),
    };

    const expectedEmailMessage = {
      source: "NTS-App-Fintech-FeeExemption",
      messageId: "mock-message-id",
      body: expectedBody,
    };

    expect(dlqService.sendToSQS).toHaveBeenCalledWith(expectedDLQMessage);
    expect(sqsEmailService.sendToSQS).toHaveBeenCalledWith(expectedEmailMessage);
    expect(sqsService.deleteFromSQS).toHaveBeenCalledWith("mock-receipt-handle");
  });


});

