import { maskCpf } from "../../utils/maskCpf";

describe("maskCpf", () => {
  it("should mask unformatted CPF", () => {
    expect(maskCpf("12345678900")).toBe("***.456.789-**");
  });

  it("should mask formatted CPF", () => {
    expect(maskCpf("123.456.789-00")).toBe("***.456.789-**");
  });

  it("should return '***' for short input", () => {
    expect(maskCpf("12345")).toBe("***");
  });

  it("should return empty string for empty input", () => {
    expect(maskCpf("")).toBe("");
  });

  it("should return falsy value as-is", () => {
    expect(maskCpf(undefined as any)).toBeUndefined();
    expect(maskCpf(null as any)).toBeNull();
  });
});

