import { execute } from "../../index-FeeExemption";
import {
  GetUserNRC,
  GetAccessPoint,
  PostPromotion,
  ProcessUserPromotion,
} from "../application";
import { SqsService } from "../infrastructure";
import { context } from '../../main-FeeExemption'
import { Callback, GraphQlService } from "libAppCommons";
import { SQS } from "@aws-sdk/client-sqs";


jest.mock("libAppCommons", () => ({
  Callback: jest.fn().mockImplementation(() => ({
    send: jest.fn()
  })),
  GraphQlService: jest.fn(),
}));

jest.mock("../application", () => ({
  ProcessUserPromotion: jest.fn().mockImplementation(() => ({
    execute: jest.fn(),
  })),
  GetUserNRC: jest.fn(),
  GetAccessPoint: jest.fn(),
  PostPromotion: jest.fn(),
}));

jest.mock("../infrastructure", () => ({
  SqsService: jest.fn(),
}));

jest.mock("@aws-sdk/client-sqs", () => ({
  SQS: jest.fn().mockImplementation(() => ({
    sendMessage: jest.fn(),
  })),
}));

describe("execute", () => {
  const mockEvent = `{
    "Records": [
      {
        "messageId": "f1ec8b44-dbe3-4622-8657-bbda1d5ebee4",
        "receiptHandle": "",
        "body": "{\\"identification\\": \\"46963899878\\", \\"productCode\\": \\"760\\", \\"productDescription\\": \\"AMEX MAGENTA\\", \\"promotionCode\\": \\"1\\", \\"promotionDescription\\": \\"Isenção de mensalidade conforme spending\\", \\"postingDate\\": \\"2025-01-14\\", \\"promotionValidityDate\\": \\"2025-02-14\\"}",
        "attributes": {
          "ApproximateReceiveCount": "1",
          "AWSTraceHeader": "Root=1-67869bec-65c15e7640fe265968aec4d6;Parent=34aa30f76cf2859c;Sampled=0;Lineage=1:477a3c93:0",
          "SentTimestamp": "1736874989258",
          "SenderId": "AROASNJ55HVIUVOXPUCTJ:trigger_sqs_isencao_mensalidade",
          "ApproximateFirstReceiveTimestamp": "1736875019258"
        },
        "messageAttributes": {},
        "md5OfBody": "c0d7f5822949d9311e509223922d7b14",
        "eventSource": "aws:sqs",
        "eventSourceARN": "arn:aws:sqs:sa-east-1:146496228606:APP_ISENCAO_MENSALIDADE_CARTAO",
        "awsRegion": "sa-east-1"
      }
    ]
  }`;
  const mockContext = context;
  const mockCallback = jest.fn();

  afterEach(() => {
    jest.clearAllMocks();
  });
  test("Deve executar com sucesso e retornar status SUCCESS", async () => {
    const mockCallbackInstance = { send: jest.fn() };
    (Callback as jest.Mock).mockImplementation(() => mockCallbackInstance);

    const mockProcessUserPromotion = {
      execute: jest.fn().mockResolvedValue("Promoção aplicada com sucesso."),
    };
    (ProcessUserPromotion as jest.Mock).mockImplementation(() => mockProcessUserPromotion);

    await execute(JSON.parse(mockEvent), mockContext, mockCallback);

    const expectedRecord = JSON.parse(mockEvent).Records[0];
    expectedRecord.body = expectedRecord.body; 

    expect(mockProcessUserPromotion.execute).toHaveBeenCalledWith(expectedRecord);

    expect(mockCallbackInstance.send).toHaveBeenCalledWith(null, {
      status: {
        codigoRetorno: 0,
        mensagem: "Promoção aplicada com sucesso.",
      },
    });
  });


  test("Deve capturar erros e retornar status ERROR", async () => {
    const mockCallbackInstance = { send: jest.fn() };
    (Callback as jest.Mock).mockImplementation(() => mockCallbackInstance);

    const mockProcessUserPromotion = {
      execute: jest.fn().mockRejectedValue(new Error("Execution error")),
    };
    (ProcessUserPromotion as jest.Mock).mockImplementation(() => mockProcessUserPromotion);

    await execute(JSON.parse(mockEvent), mockContext, mockCallback);

    const expectedRecord = JSON.parse(mockEvent).Records[0];
    expectedRecord.body =expectedRecord.body; 

    expect(mockProcessUserPromotion.execute).toHaveBeenCalledWith(expectedRecord);

    expect(mockCallbackInstance.send).toHaveBeenCalledWith({
      status: {
        codigoRetorno: -1,
        mensagem: "Error: Execution error",
      },
    });
  });



  test("Deve configurar corretamente todas as dependências", async () => {
    const graphQlService = new GraphQlService();
    const sqs = new SQS({});
    const getUser = new GetUserNRC(graphQlService);
    const getAccessPoint = new GetAccessPoint(graphQlService);
    const postPromotion = new PostPromotion(graphQlService);
    const dlqService = new SqsService(
      sqs,
      process.env.QUEUE_APP_ISENCAO_MENSALIDADE_CARTAO_ERRO!
    );

    const mockProcessUserPromotion = {
      execute: jest.fn(),
    };
    (ProcessUserPromotion as jest.Mock).mockImplementation(() => mockProcessUserPromotion);

    await execute(mockEvent, mockContext, mockCallback);

    expect(GraphQlService).toHaveBeenCalledTimes(2);
    expect(SQS).toHaveBeenCalledWith({
      region: "sa-east-1",
    });
    expect(GetUserNRC).toHaveBeenCalledWith(graphQlService);
    expect(GetAccessPoint).toHaveBeenCalledWith(graphQlService);
    expect(PostPromotion).toHaveBeenCalledWith(graphQlService);
    expect(SqsService).toHaveBeenCalledWith(
      sqs,
      process.env.QUEUE_APP_ISENCAO_MENSALIDADE_CARTAO_ERRO!
    );
  });
});

