export const maskCpf = (cpf: string): string => {
  if (!cpf) return cpf;

  const digits = cpf.replace(/\D/g, "");

  if (digits.length < 11) return "***";

  return `***.${digits.substring(3, 6)}.${digits.substring(6, 9)}-**`;
};

