import { Callback, GraphQlService } from "libAppCommons";
import {
  GetAccessPoint,
  GetUserNRC,
  PostPromotion,
  ProcessUserPromotion,
} from "./src/application/index";
import { SqsService } from "./src/infrastructure/index";
import { SQS } from "@aws-sdk/client-sqs";
import { Context } from 'aws-lambda';
import { Console } from "libStpInvoke";

export const execute = async (event: any, context: Context, callback: any) => {
  Console.prepareStream(event, context)
  const callbackSTP = new Callback(event, callback, context);

  const record = typeof event === "string" ? JSON.parse(event).Records[0] : event.Records[0];

  try {
    const sqs = new SQS({
      region: "sa-east-1",
    });

    const sqsEmailService = new SqsService(
      sqs,
      process.env.QUEUE_APP_ISENCAO_MENSALIDADE_CARTAO_EMAIL!
    );

    const maxReceiveCount = Number(process.env.MAX_RECEIVE_COUNT ?? "3");

    const graphQlService = new GraphQlService();
    const getUser = new GetUserNRC(graphQlService);
    const getAccessPoint = new GetAccessPoint(graphQlService);
    const postPromotion = new PostPromotion(graphQlService);

    const processUserPromotion = new ProcessUserPromotion(
      getUser,
      getAccessPoint,
      postPromotion,
      sqsEmailService,
      maxReceiveCount
    );

    const processPromotion = await processUserPromotion.execute(record);

    const response = {
      status: {
        codigoRetorno: 0,
        mensagem: processPromotion,
      },
    };

    return callbackSTP.send(null, response);
  } catch (error) {
    const response = {
      status: {
        codigoRetorno: -1,
        mensagem: String(error),
      },
    };
    callbackSTP.send(response);
  }
};

