import { SqsService } from "../../infrastructure";
import { GetAccessPoint, GetUserNRC, PostPromotion, ProcessUserPromotion } from "../../application";
import { COMPANY_IDENTIFICATION } from "../../constants";

jest.mock("libStpInvoke", () => ({
  Console: {
    error: jest.fn(),
    info: jest.fn(),
    prepareStream: jest.fn(),
  },
}));

const { Console } = require("libStpInvoke");

describe("ProcessUserPromotion", () => {
  let processUserPromotion: ProcessUserPromotion;
  let getUser: jest.Mocked<GetUserNRC>;
  let getAccessPoint: jest.Mocked<GetAccessPoint>;
  let postPromotion: jest.Mocked<PostPromotion>;
  let sqsEmailService: jest.Mocked<SqsService>;
  const maxReceiveCount = 3;

  const buildEvent = (overrides: Record<string, any> = {}) => ({
    messageId: "mock-message-id",
    receiptHandle: "mock-receipt-handle",
    body: JSON.stringify({
      identification: "12345678900",
      productCode: "1",
      productDescription: "Test Product",
      promotionCode: "2",
      promotionDescription: "Test Promotion",
      promotionValidityDate: "2024-12-31",
      postingDate: "2024-12-01",
    }),
    attributes: {
      ApproximateReceiveCount: "1",
      SentTimestamp: "1234567890",
      SenderId: "sender-id",
      ApproximateFirstReceiveTimestamp: "1234567890",
    },
    messageAttributes: {},
    md5OfBody: "mock-md5",
    eventSource: "aws:sqs",
    eventSourceARN: "arn:aws:sqs:sa-east-1:123456789012:APP_ISENCAO_MENSALIDADE_CARTAO",
    awsRegion: "sa-east-1",
    ...overrides,
  });

  beforeEach(() => {
    getUser = {
      execute: jest.fn(),
    } as unknown as jest.Mocked<GetUserNRC>;

    getAccessPoint = {
      execute: jest.fn(),
    } as unknown as jest.Mocked<GetAccessPoint>;

    postPromotion = {
      execute: jest.fn(),
    } as unknown as jest.Mocked<PostPromotion>;

    sqsEmailService = {
      sendToSQS: jest.fn(),
    } as unknown as jest.Mocked<SqsService>;

    processUserPromotion = new ProcessUserPromotion(
      getUser,
      getAccessPoint,
      postPromotion,
      sqsEmailService,
      maxReceiveCount
    );
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it("should process user promotion successfully", async () => {
    const event = buildEvent();

    (getUser.execute as jest.Mock).mockResolvedValue("user-nrc");
    (getAccessPoint.execute as jest.Mock).mockResolvedValue({ identification: "product-id" });
    (postPromotion.execute as jest.Mock).mockResolvedValue({});

    await processUserPromotion.execute(event);

    expect(getUser.execute).toHaveBeenCalledWith(COMPANY_IDENTIFICATION, "12345678900");
    expect(getAccessPoint.execute).toHaveBeenCalledWith(COMPANY_IDENTIFICATION, "user-nrc");
    expect(postPromotion.execute).toHaveBeenCalledWith("user-nrc", "product-id", COMPANY_IDENTIFICATION);
    expect(sqsEmailService.sendToSQS).not.toHaveBeenCalled();
  });

  it("should log structured error and NOT send email on intermediate attempt", async () => {
    const event = buildEvent({
      attributes: {
        ApproximateReceiveCount: "1",
        SentTimestamp: "1234567890",
        SenderId: "sender-id",
        ApproximateFirstReceiveTimestamp: "1234567890",
      },
    });

    (getUser.execute as jest.Mock).mockRejectedValue(new Error("Customer not found"));

    await expect(processUserPromotion.execute(event)).rejects.toThrow("Customer not found");

    expect(Console.error).toHaveBeenCalledTimes(1);
    const logPayload = JSON.parse((Console.error as jest.Mock).mock.calls[0][0]);
    expect(logPayload).toMatchObject({
      level: "ERROR",
      action: "PROMOTION_FAILURE",
      messageId: "mock-message-id",
      identification: "***.456.789-**",
      errorType: "business",
      errorMessage: "Customer not found",
      receiveCount: 1,
      maxReceiveCount: 3,
      isFinalAttempt: false,
    });

    expect(sqsEmailService.sendToSQS).not.toHaveBeenCalled();
  });

  it("should log structured error and send email on final attempt", async () => {
    const event = buildEvent({
      attributes: {
        ApproximateReceiveCount: "3",
        SentTimestamp: "1234567890",
        SenderId: "sender-id",
        ApproximateFirstReceiveTimestamp: "1234567890",
      },
    });

    (getUser.execute as jest.Mock).mockRejectedValue(new Error("Could not load credentials from any providers"));

    await expect(processUserPromotion.execute(event)).rejects.toThrow("Could not load credentials from any providers");

    const logPayload = JSON.parse((Console.error as jest.Mock).mock.calls[0][0]);
    expect(logPayload).toMatchObject({
      level: "ERROR",
      action: "PROMOTION_FAILURE",
      errorType: "system",
      receiveCount: 3,
      isFinalAttempt: true,
    });

    expect(sqsEmailService.sendToSQS).toHaveBeenCalledTimes(1);
    const emailArg = (sqsEmailService.sendToSQS as jest.Mock).mock.calls[0][0];
    expect(emailArg).toMatchObject({
      source: "NTS-App-Fintech-FeeExemption",
      messageId: "mock-message-id",
      body: expect.objectContaining({
        identification: "12345678900",
        error: "Could not load credentials from any providers",
        errorType: "system",
      }),
    });
  });

  it("should classify business errors correctly in log", async () => {
    const event = buildEvent({
      attributes: {
        ApproximateReceiveCount: "2",
        SentTimestamp: "1234567890",
        SenderId: "sender-id",
        ApproximateFirstReceiveTimestamp: "1234567890",
      },
    });

    (getUser.execute as jest.Mock).mockResolvedValue("user-nrc");
    (getAccessPoint.execute as jest.Mock).mockRejectedValue(new Error("Contracted product not found"));

    await expect(processUserPromotion.execute(event)).rejects.toThrow("Contracted product not found");

    const logPayload = JSON.parse((Console.error as jest.Mock).mock.calls[0][0]);
    expect(logPayload.errorType).toBe("business");
    expect(logPayload.isFinalAttempt).toBe(false);
    expect(sqsEmailService.sendToSQS).not.toHaveBeenCalled();
  });
});

