#!/usr/bin/env bun
/**
 * Poll SQS queues for messages (non-destructive, visibility-timeout 0).
 *
 * Usage:
 *   bun scripts/sqs-poll.ts              # polls all queues once
 *   bun scripts/sqs-poll.ts --watch      # continuous polling
 *   bun scripts/sqs-poll.ts --queue dlq  # poll specific queue (main|dlq|dlqOld|email)
 */
import { QUEUES, env } from "./config";

const args = process.argv.slice(2);
const watch = args.includes("--watch");
const queueArg = args.find((_, i, a) => a[i - 1] === "--queue") as keyof typeof QUEUES | undefined;
const queues = queueArg ? { [queueArg]: QUEUES[queueArg] } : QUEUES;

async function poll(name: string, url: string) {
  const proc = Bun.spawn([
    "aws", "sqs", "receive-message",
    "--queue-url", url,
    "--max-number-of-messages", "10",
    "--attribute-names", "All",
    "--message-attribute-names", "All",
    "--visibility-timeout", "0",
    "--wait-time-seconds", watch ? "20" : "0",
    "--region", env.AWS_REGION,
  ], { env, stdout: "pipe", stderr: "pipe" });

  const out = await new Response(proc.stdout).text();
  const err = await new Response(proc.stderr).text();
  if (err.trim()) console.error(`[${name}] ERROR: ${err.trim()}`);

  if (!out.trim()) {
    console.log(`[${name}] empty`);
    return;
  }

  const data = JSON.parse(out);
  if (!data.Messages?.length) {
    console.log(`[${name}] empty`);
    return;
  }

  for (const msg of data.Messages) {
    const ts = new Date().toLocaleTimeString("pt-BR");
    console.log(`\n[${name}] ${ts} >>> MESSAGE <<<`);
    console.log(`  messageId: ${msg.MessageId}`);
    console.log(`  receiveCount: ${msg.Attributes?.ApproximateReceiveCount}`);
    try {
      const body = JSON.parse(msg.Body);
      console.log(`  body:`, JSON.stringify(body, null, 2));
    } catch {
      console.log(`  body (raw): ${msg.Body}`);
    }
  }
}

async function run() {
  const ts = new Date().toLocaleTimeString("pt-BR");
  console.log(`--- ${ts} polling ${Object.keys(queues).join(", ")} ---`);
  await Promise.all(Object.entries(queues).map(([name, url]) => poll(name, url)));
}

if (watch) {
  console.log("Watching queues (Ctrl+C to stop)...\n");
  while (true) await run();
} else {
  await run();
}

