#!/usr/bin/env bun
/**
 * Show message counts and configuration for all related SQS queues.
 *
 * Usage:
 *   bun scripts/sqs-status.ts
 */
import { QUEUES, env } from "./config";

async function getAttributes(name: string, url: string) {
  const proc = Bun.spawn([
    "aws", "sqs", "get-queue-attributes",
    "--queue-url", url,
    "--attribute-names", "All",
    "--region", env.AWS_REGION,
  ], { env, stdout: "pipe", stderr: "pipe" });

  const out = await new Response(proc.stdout).text();
  const err = await new Response(proc.stderr).text();
  if (err.trim()) { console.error(`[${name}] ${err.trim()}`); return; }
  if (!out.trim()) { console.log(`[${name}] no response`); return; }

  const { Attributes: a } = JSON.parse(out);
  const redrive = a.RedrivePolicy ? JSON.parse(a.RedrivePolicy) : null;

  console.log(`\n[${name}]`);
  console.log(`  Messages Available:    ${a.ApproximateNumberOfMessages}`);
  console.log(`  Messages In Flight:    ${a.ApproximateNumberOfMessagesNotVisible}`);
  console.log(`  Messages Delayed:      ${a.ApproximateNumberOfMessagesDelayed}`);
  console.log(`  VisibilityTimeout:     ${a.VisibilityTimeout}s`);
  console.log(`  DelaySeconds:          ${a.DelaySeconds}s`);
  console.log(`  MessageRetentionPeriod:${(Number(a.MessageRetentionPeriod) / 86400).toFixed(0)} days`);
  if (redrive) {
    const dlqName = redrive.deadLetterTargetArn.split(":").pop();
    console.log(`  RedrivePolicy:         → ${dlqName} (maxReceiveCount: ${redrive.maxReceiveCount})`);
  } else {
    console.log(`  RedrivePolicy:         none (terminal queue)`);
  }
}

console.log("=== SQS Queue Status ===");
for (const [name, url] of Object.entries(QUEUES)) {
  await getAttributes(name, url);
}

