#!/usr/bin/env bun
/**
 * Tail CloudWatch Logs for the FeeExemption Lambda in real-time.
 *
 * Usage:
 *   bun scripts/logs-tail.ts              # last 30min + follow
 *   bun scripts/logs-tail.ts --since 2h   # last 2 hours + follow
 *   bun scripts/logs-tail.ts --no-follow  # one-shot, no streaming
 */
import { LOG_GROUP, env } from "./config";

const args = process.argv.slice(2);
const sinceIdx = args.indexOf("--since");
const since = sinceIdx !== -1 ? args[sinceIdx + 1] : "30m";
const follow = !args.includes("--no-follow");

const cmd = [
  "aws", "logs", "tail", LOG_GROUP,
  "--since", since,
  "--format", "short",
  "--region", env.AWS_REGION,
  ...(follow ? ["--follow"] : []),
];

console.log(`Tailing ${LOG_GROUP} (since ${since}, follow=${follow})`);
console.log(`Ctrl+C to stop\n`);

const proc = Bun.spawn(cmd, { env, stdout: "inherit", stderr: "inherit" });
await proc.exited;

