#!/usr/bin/env bun
/**
 * Fetch the last N Lambda invocations from CloudWatch Logs.
 *
 * Usage:
 *   bun scripts/logs-last.ts          # last 3 invocations
 *   bun scripts/logs-last.ts 10       # last 10 invocations
 */
import { LOG_GROUP, env } from "./config";

const limit = Number(process.argv[2]) || 3;

const streamsProc = Bun.spawn([
  "aws", "logs", "describe-log-streams",
  "--log-group-name", LOG_GROUP,
  "--order-by", "LastEventTime",
  "--descending",
  "--limit", String(limit),
  "--region", env.AWS_REGION,
], { env, stdout: "pipe", stderr: "pipe" });

const streamsOut = await new Response(streamsProc.stdout).text();
const streamsErr = await new Response(streamsProc.stderr).text();
if (streamsErr.trim()) { console.error(streamsErr.trim()); process.exit(1); }

const { logStreams } = JSON.parse(streamsOut);

if (!logStreams?.length) {
  console.log("No log streams found.");
  process.exit(0);
}

for (const stream of logStreams) {
  const lastEvent = new Date(stream.lastEventTimestamp).toLocaleString("pt-BR");
  console.log(`\n=== ${stream.logStreamName} (last event: ${lastEvent}) ===\n`);

  const eventsProc = Bun.spawn([
    "aws", "logs", "get-log-events",
    "--log-group-name", LOG_GROUP,
    "--log-stream-name", stream.logStreamName,
    "--start-from-head",
    "--region", env.AWS_REGION,
  ], { env, stdout: "pipe", stderr: "pipe" });

  const eventsOut = await new Response(eventsProc.stdout).text();
  const { events } = JSON.parse(eventsOut);

  for (const event of events) {
    const ts = new Date(event.timestamp).toLocaleTimeString("pt-BR");
    const msg = event.message.trim();

    if (msg.startsWith("START") || msg.startsWith("END") || msg.startsWith("REPORT") || msg.startsWith("INIT_START")) {
      console.log(`  ${ts} ${msg.split("\t").pop()}`);
      continue;
    }

    const parts = msg.split("\t");
    const level = parts[2] || "";
    const content = parts.slice(3).join("\t");

    if (level === "ERROR") {
      try {
        const parsed = JSON.parse(content);
        console.log(`  ${ts} ERROR`, JSON.stringify(parsed, null, 2));
      } catch {
        console.log(`  ${ts} ERROR ${content}`);
      }
    } else {
      console.log(`  ${ts} ${level} ${content.substring(0, 200)}`);
    }
  }
}

