/**
 * Send a test message to the main SQS queue.
 *
 * Usage:
 *   bun scripts/sqs-send-test.ts                        # default test payload
 *   bun scripts/sqs-send-test.ts --cpf 12345678900      # custom CPF
 *   bun scripts/sqs-send-test.ts --invalid              # malformed body (for error testing)
 */
import { QUEUES, env } from "./config";

const args = process.argv.slice(2);
const cpfIdx = args.indexOf("--cpf");
const cpf = cpfIdx !== -1 ? args[cpfIdx + 1] : "00000000000";
const invalid = args.includes("--invalid");

const body = invalid
  ? "INVALID_JSON{{{"
  : JSON.stringify({
      identification: cpf,
      productCode: "760",
      productDescription: "AMEX MAGENTA",
      promotionCode: "1",
      promotionDescription: "Isencao de mensalidade conforme spending",
      postingDate: new Date().toISOString().split("T")[0],
      promotionValidityDate: new Date(Date.now() + 30 * 86400000).toISOString().split("T")[0],
    });

console.log("Sending to:", QUEUES.main);
console.log("Body:", body);

const proc = Bun.spawn([
  "aws", "sqs", "send-message",
  "--queue-url", QUEUES.main,
  "--message-body", body,
  "--region", env.AWS_REGION,
], { env, stdout: "pipe", stderr: "pipe" });

const out = await new Response(proc.stdout).text();
const err = await new Response(proc.stderr).text();

if (err.trim()) {
  console.error("ERROR:", err.trim());
  process.exit(1);
}

const result = JSON.parse(out);
console.log("\nSent successfully!");
console.log(`  MessageId: ${result.MessageId}`);
console.log(`  MD5: ${result.MD5OfMessageBody}`);

